// Push Notifications для новостей
class PushNotifications {
  constructor() {
    this.init();
  }

  async init() {
    if ('serviceWorker' in navigator && 'PushManager' in window) {
      try {
        // Регистрация Service Worker
        const registration = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
        console.log('Service Worker registered');

        // Запрос разрешения на уведомления
        const permission = await Notification.requestPermission();
        if (permission === 'granted') {
          console.log('Notification permission granted');
          
          // Подписка на push уведомления
          const subscription = await registration.pushManager.subscribe({
            userVisibleOnly: true,
            applicationServerKey: this.urlBase64ToUint8Array('your-vapid-public-key')
          });

          // Отправка подписки на сервер
          await this.sendSubscriptionToServer(subscription);
        }
      } catch (error) {
        console.error('Error initializing push notifications:', error);
      }
    }
  }

  urlBase64ToUint8Array(base64String: string): Uint8Array {
    const padding = '='.repeat((4 - base64String.length % 4) % 4);
    const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
    const rawData = window.atob(base64);
    const outputArray = new Uint8Array(rawData.length);
    
    for (let i = 0; i < rawData.length; ++i) {
      outputArray[i] = rawData.charCodeAt(i);
    }
    
    return outputArray as any;
  }

  async sendSubscriptionToServer(subscription: PushSubscription) {
    try {
      await fetch('/api/subscribe', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(subscription)
      });
    } catch (error) {
      console.error('Error sending subscription:', error);
    }
  }

  // Показ локального уведомления
  showLocalNotification(title: string, body: string, data?: any) {
    if ('Notification' in navigator && Notification.permission === 'granted') {
      const notification = new Notification(title, {
        body,
        icon: '/favicon.ico',
        badge: '/favicon.ico',
        tag: 'news',
        requireInteraction: true,
        data: data || {}
      });

      notification.onclick = () => {
        window.focus();
        if (data?.newsId) {
          window.location.hash = '#info';
        }
        notification.close();
      };

      // Автозакрытие через 10 секунд
      setTimeout(() => notification.close(), 10000);
    }
  }
}

export const pushNotifications = new PushNotifications();
