import React, { useState, useEffect } from 'react';
import { api } from '../api';
import { Calculator, TrendingUp, Wallet, ChevronDown, ChevronUp } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

interface SalaryPageProps {
  isAdmin: boolean;
}

export default function SalaryPage({ isAdmin }: SalaryPageProps) {
  const [reports, setReports] = useState<any[]>([]);
  const [rates, setRates] = useState<any[]>([]);
  const [expandedWorker, setExpandedWorker] = useState<string | null>(null);
  const [showPaid, setShowPaid] = useState(false);

  useEffect(() => {
    if (isAdmin) {
      refreshData();
    }
  }, [isAdmin]);

  const refreshData = () => {
    Promise.all([
      api.getReports(),
      api.getRates()
    ]).then(([reportsData, ratesData]) => {
      setReports(reportsData.filter((r: any) => r.status === 'confirmed'));
      setRates(ratesData);
    });
  };

  const handleMarkPaid = async (reportIds: number[]) => {
    if (confirm(`Отметить ${reportIds.length} отчетов как выплаченные?`)) {
      await api.markReportsAsPaid(reportIds);
      refreshData();
    }
  };

  const calculateSalary = (report: any) => {
    // Priority: Worker > Day > Point > City
    const workerRate = rates.find(r => r.type === 'worker' && r.target_id === report.worker_id);
    const dayRate = rates.find(r => r.type === 'day' && r.date === report.date);
    const pointRate = rates.find(r => r.type === 'point' && r.target_id === report.point_id.toString());
    const cityRate = rates.find(r => r.type === 'city' && r.target_id === report.city);

    // Priority of importance: 1. Worker, 2. Day, 3. Point, 4. City
    const rate = workerRate?.rate || dayRate?.rate || pointRate?.rate || cityRate?.rate || 0;
    const percentage = workerRate?.percentage || dayRate?.percentage || pointRate?.percentage || cityRate?.percentage || 0;
    
    // Calculate base salary
    const basePay = report.hours * rate;
    const bonusPay = report.cash * (percentage / 100);
    const total = basePay + bonusPay;
    
    // Apply rounding to 50 rubles using API function
    const roundedTotal = api.calculateSalary(1, total);
    
    return {
      total: roundedTotal,
      basePay,
      bonusPay,
      purchase: report.purchase,
      rate,
      percentage
    };
  };

  // Group by worker ID, Name and City to handle conflicts
  const workerSalaries = reports
    .filter(r => showPaid ? true : !r.is_paid)
    .reduce((acc: any, report: any) => {
      const calc = calculateSalary(report);
      const key = `${report.worker_id}_${report.worker_name}_${report.city}`;
      if (!acc[key]) {
        acc[key] = {
          id: report.worker_id,
          name: report.worker_name,
          city: report.city,
          total: 0,
          hours: 0,
          cash: 0,
          purchase: 0,
          reports: [],
          reportIds: [] // Добавляем для отслеживания уникальных отчетов
        };
      }
      acc[key].total += calc.total;
      acc[key].hours += report.hours;
      acc[key].cash += report.cash;
      acc[key].purchase += report.purchase;
      acc[key].reports.push({ ...report, calc });
      acc[key].reportIds.push(report.id); // Сохраняем ID отчета
      return acc;
    }, {});

  const workers = Object.values(workerSalaries);

  if (!isAdmin) return <div className="p-8 text-center font-bold text-red-500">Доступ запрещен</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black tracking-tight uppercase">Расчет зарплаты</h2>
        <button 
          onClick={() => setShowPaid(!showPaid)}
          className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${showPaid ? 'bg-stone-900 text-white' : 'bg-stone-100 text-stone-500'}`}
        >
          {showPaid ? 'Скрыть выплаченные' : 'Показать все'}
        </button>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="bg-white rounded-3xl p-5 border border-stone-200 shadow-sm">
          <div className="bg-emerald-100 w-10 h-10 rounded-2xl flex items-center justify-center mb-3">
            <Wallet className="text-emerald-600 w-5 h-5" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">К выплате</p>
          <p className="text-xl font-black text-stone-900">
            {workers.reduce((sum: number, w: any) => sum + w.total, 0).toLocaleString()} ₽
          </p>
        </div>
        <div className="bg-white rounded-3xl p-5 border border-stone-200 shadow-sm">
          <div className="bg-blue-100 w-10 h-10 rounded-2xl flex items-center justify-center mb-3">
            <TrendingUp className="text-blue-600 w-5 h-5" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Касса</p>
          <p className="text-xl font-black text-stone-900">
            {workers.reduce((sum: number, w: any) => sum + w.cash, 0).toLocaleString()} ₽
          </p>
        </div>
        <div className="bg-white rounded-3xl p-5 border border-stone-200 shadow-sm">
          <div className="bg-amber-100 w-10 h-10 rounded-2xl flex items-center justify-center mb-3">
            <TrendingUp className="text-amber-600 w-5 h-5" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Закуп</p>
          <p className="text-xl font-black text-stone-900">
            {workers.reduce((sum: number, w: any) => sum + w.purchase, 0).toLocaleString()} ₽
          </p>
        </div>
      </div>

      <div className="space-y-4">
        {workers.map((worker: any) => (
          <div key={`salary-${worker.id}-${worker.city}-${worker.name.replace(/\s+/g, '-')}`} className="bg-white rounded-3xl border border-stone-200 shadow-sm overflow-hidden">
            <button 
              onClick={() => setExpandedWorker(expandedWorker === worker.id ? null : worker.id)}
              className="w-full p-5 flex items-center justify-between text-left"
            >
              <div className="flex items-center gap-4">
                <div className="bg-stone-100 w-12 h-12 rounded-2xl flex items-center justify-center text-stone-500 font-black text-xl">
                  {worker.name[0]}
                </div>
                <div>
                  <p className="font-black text-lg leading-tight">{worker.name}</p>
                  <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mt-1">ID: {worker.id}</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <p className="font-black text-emerald-600 text-xl">{worker.total.toLocaleString()} ₽</p>
                  <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">{worker.hours} ч</p>
                </div>
                {expandedWorker === worker.id ? <ChevronUp className="text-stone-300" /> : <ChevronDown className="text-stone-300" />}
              </div>
            </button>

            <AnimatePresence>
              {expandedWorker === worker.id && (
                <motion.div 
                  initial={{ height: 0, opacity: 0 }}
                  animate={{ height: 'auto', opacity: 1 }}
                  exit={{ height: 0, opacity: 0 }}
                  className="border-t border-stone-100 bg-stone-50/50"
                >
                  <div className="p-5 space-y-4">
                    <div className="flex justify-between items-center bg-stone-100 p-4 rounded-2xl">
                      <div>
                        <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">К выплате</p>
                        <p className="font-black text-emerald-600 text-xl">{worker.total.toLocaleString()} ₽</p>
                      </div>
                      <button 
                        onClick={() => handleMarkPaid(worker.reports.filter((r: any) => !r.is_paid).map((r: any) => r.id))}
                        disabled={worker.reports.every((r: any) => r.is_paid)}
                        className="bg-emerald-600 text-white px-6 py-2 rounded-xl font-bold text-xs shadow-lg shadow-emerald-600/20 disabled:opacity-50 disabled:shadow-none"
                      >
                        Выплачено
                      </button>
                    </div>

                    {worker.reports.map((report: any) => (
                      <div key={report.id} className={`bg-white rounded-2xl p-4 border shadow-sm ${report.is_paid ? 'border-stone-100 opacity-60' : 'border-stone-100'}`}>
                        <div className="flex justify-between items-start mb-3">
                          <div>
                            <div className="flex items-center gap-2">
                              <p className="font-bold text-sm text-stone-900">{report.point_name}</p>
                              {report.is_paid && <span className="text-[8px] bg-stone-100 text-stone-400 px-1.5 py-0.5 rounded uppercase font-black">Выплачено</span>}
                            </div>
                            <p className="text-[10px] font-bold text-stone-400 uppercase">{new Date(report.date).toLocaleDateString('ru-RU')}</p>
                          </div>
                          <p className="font-black text-emerald-600">{report.calc.total.toLocaleString()} ₽</p>
                        </div>
                        <div className="grid grid-cols-3 gap-2 text-[10px] font-bold uppercase tracking-wider text-stone-500">
                          <div>
                            <p className="text-stone-400 mb-0.5">Часы</p>
                            <p className="text-stone-700">{report.hours} × {report.calc.rate}</p>
                          </div>
                          <div>
                            <p className="text-stone-400 mb-0.5">Касса</p>
                            <p className="text-stone-700">{report.cash} × {report.calc.percentage}%</p>
                          </div>
                          <div>
                            <p className="text-stone-400 mb-0.5">Закуп</p>
                            <p className="text-stone-700">{report.purchase}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        ))}
        {workers.length === 0 && (
          <div className="text-center py-12 text-stone-400 font-medium">
            Нет подтвержденных отчетов для расчета
          </div>
        )}
      </div>
    </div>
  );
}
