import React, { useState, useEffect } from 'react';
import { 
  Info, 
  FileText, 
  Users, 
  ShieldCheck, 
  Calculator, 
  Settings, 
  TrendingUp,
  ChevronRight,
  MapPin,
  Lock,
  LogOut,
  Menu,
  X,
  Sun,
  Moon
} from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

// Pages
import InfoPage from './pages/InfoPage';
import ReportPage from './pages/ReportPage';
import WorkersPage from './pages/WorkersPage';
import ModerationPage from './pages/ModerationPage';
import SalaryPage from './pages/SalaryPage';
import AdminSettings from './pages/AdminSettings';
import StatsPage from './pages/StatsPage';
import { pushNotifications } from './pushNotifications';

export type City = 'chelyabinsk' | 'ozersk';
export type Theme = 'light' | 'dark';

export default function App() {
  const [city, setCity] = useState<City>('chelyabinsk');
  const [isAdmin, setIsAdmin] = useState(false);
  const [activePage, setActivePage] = useState('info');
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('theme');
    return (saved as Theme) || 'light';
  });

  useEffect(() => {
    pushNotifications.init();
    const savedTheme = localStorage.getItem('theme') as Theme || 'light';
    setTheme(savedTheme);
    document.documentElement.classList.toggle('dark', savedTheme === 'dark');
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  const handleAdminLogin = () => {
    if (adminPassword === '14888') {
      setIsAdmin(true);
      setShowAdminLogin(false);
      setAdminPassword('');
    } else {
      alert('Неверный пароль');
    }
  };

  const navItems = [
    { id: 'info', label: 'Инфо', icon: Info, roles: ['user', 'admin'] },
    { id: 'report', label: 'Отчет', icon: FileText, roles: ['user', 'admin'] },
    { id: 'workers', label: 'Сотрудники', icon: Users, roles: ['user', 'admin'] },
    { id: 'moderation', label: 'Модерация', icon: ShieldCheck, roles: ['admin'] },
    { id: 'salary', label: 'Зарплата', icon: Calculator, roles: ['admin'] },
    { id: 'stats', label: 'Статистика', icon: TrendingUp, roles: ['admin'] },
    { id: 'settings', label: 'Настройки', icon: Settings, roles: ['admin'] },
  ];

  const filteredNavItems = navItems.filter(item => 
    item.roles.includes('user') || (item.roles.includes('admin') && isAdmin)
  );

  const renderPage = () => {
    switch (activePage) {
      case 'info': return <InfoPage city={city} isAdmin={isAdmin} />;
      case 'report': return <ReportPage city={city} />;
      case 'workers': return <WorkersPage isAdmin={isAdmin} />;
      case 'moderation': return <ModerationPage isAdmin={isAdmin} />;
      case 'salary': return <SalaryPage isAdmin={isAdmin} />;
      case 'stats': return <StatsPage isAdmin={isAdmin} />;
      case 'settings': return <AdminSettings isAdmin={isAdmin} city={city} />;
      default: return <InfoPage city={city} isAdmin={isAdmin} />;
    }
  };

  return (
    <div className="min-h-screen bg-stone-100 text-stone-900 font-sans pb-20">
      {/* Header */}
      <header className="bg-white border-b border-stone-200 sticky top-0 z-40 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-600 p-1.5 rounded-lg">
            <Calculator className="text-white w-5 h-5" />
          </div>
          <h1 className="font-bold text-lg tracking-tight">WorkTracker</h1>
        </div>

        <div className="flex items-center gap-3">
          {/* Theme Switcher */}
          <button 
            onClick={toggleTheme}
            className="p-2 text-stone-500 hover:text-stone-700 transition-colors bg-stone-100 rounded-full"
          >
            {theme === 'light' ? <Moon className="w-4 h-4" /> : <Sun className="w-4 h-4" />}
          </button>

          {/* City Switcher */}
          <div className="flex bg-stone-100 p-1 rounded-full text-xs font-medium">
            <button 
              onClick={() => setCity('chelyabinsk')}
              className={`px-3 py-1 rounded-full transition-all ${city === 'chelyabinsk' ? 'bg-white shadow-sm text-emerald-700' : 'text-stone-500'}`}
            >
              ЧБ
            </button>
            <button 
              onClick={() => setCity('ozersk')}
              className={`px-3 py-1 rounded-full transition-all ${city === 'ozersk' ? 'bg-white shadow-sm text-emerald-700' : 'text-stone-500'}`}
            >
              ОЗ
            </button>
          </div>

          {isAdmin ? (
            <button 
              onClick={() => setIsAdmin(false)}
              className="p-2 text-stone-500 hover:text-red-600 transition-colors"
            >
              <LogOut className="w-5 h-5" />
            </button>
          ) : (
            <button 
              onClick={() => setShowAdminLogin(true)}
              className="p-2 text-stone-500 hover:text-emerald-600 transition-colors"
            >
              <Lock className="w-5 h-5" />
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className={`mx-auto p-4 transition-all duration-300 ${activePage === 'stats' ? 'max-w-4xl' : 'max-w-md'}`}>
        <AnimatePresence mode="wait">
          <motion.div
            key={activePage + city}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            transition={{ duration: 0.2 }}
          >
            {renderPage()}
          </motion.div>
        </AnimatePresence>
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-stone-200 px-2 py-1 z-40 shadow-[0_-2px_10px_rgba(0,0,0,0.05)]">
        <div className="max-w-md mx-auto flex justify-around items-center">
          {filteredNavItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActivePage(item.id)}
              className={`flex flex-col items-center gap-1 p-2 min-w-[64px] transition-all relative ${
                activePage === item.id ? 'text-emerald-600' : 'text-stone-400'
              }`}
            >
              <item.icon className={`w-5 h-5 ${activePage === item.id ? 'stroke-[2.5px]' : 'stroke-2'}`} />
              <span className="text-[10px] font-semibold uppercase tracking-wider">{item.label}</span>
              {activePage === item.id && (
                <motion.div 
                  layoutId="nav-indicator"
                  className="absolute -top-1 w-8 h-1 bg-emerald-600 rounded-full"
                />
              )}
            </button>
          ))}
        </div>
      </nav>

      {/* Admin Login Modal */}
      <AnimatePresence>
        {showAdminLogin && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setShowAdminLogin(false)}
              className="absolute inset-0 bg-stone-900/60 backdrop-blur-sm"
            />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="relative bg-white w-full max-w-xs rounded-2xl shadow-2xl p-6 overflow-hidden"
            >
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold">Вход для админа</h2>
                <button onClick={() => setShowAdminLogin(false)} className="text-stone-400">
                  <X className="w-6 h-6" />
                </button>
              </div>
              
              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-bold text-stone-500 uppercase mb-1">Пароль</label>
                  <input 
                    type="password" 
                    value={adminPassword}
                    onChange={(e) => setAdminPassword(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleAdminLogin()}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    placeholder="•••••"
                    autoFocus
                  />
                </div>
                <button 
                  onClick={handleAdminLogin}
                  className="w-full bg-emerald-600 text-white font-bold py-3 rounded-xl shadow-lg shadow-emerald-600/20 active:scale-95 transition-all"
                >
                  Войти
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}
