import React, { useState, useEffect } from 'react';
import { City } from '../App';
import { api } from '../api';
import { Send, AlertCircle, CheckCircle2 } from 'lucide-react';
import { motion } from 'motion/react';

interface ReportPageProps {
  city: City;
}

export default function ReportPage({ city }: ReportPageProps) {
  const [points, setPoints] = useState<any[]>([]);
  const [workerId, setWorkerId] = useState('');
  const [workerName, setWorkerName] = useState('');
  const [selectedPointId, setSelectedPointId] = useState<string>('');
  const [hours, setHours] = useState('');
  const [cash, setCash] = useState('');
  const [cash2, setCash2] = useState('');
  const [purchase, setPurchase] = useState('');
  const [comment, setComment] = useState('');
  const [password, setPassword] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const selectedPoint = points.find(p => p.id.toString() === selectedPointId);
  const mergedPoint = selectedPoint?.is_merged ? points.find(p => p.id === selectedPoint.merged_with) : null;

  // Available dates (today + last 3 days)
  const dates = Array.from({ length: 4 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() - i);
    return d.toISOString().split('T')[0];
  });

  useEffect(() => {
    api.getPoints(city).then(setPoints);
  }, [city]);

  useEffect(() => {
    if (workerId.length >= 1) {
      // Ищем сотрудника с учетом даты отчета
      api.getWorkerByIdAndDate(workerId, date).then(worker => {
        if (worker && worker.city === city) {
          setWorkerName(worker.name);
          setError('');
        } else {
          // Если не нашли по дате, пробуем обычный поиск для обратной совместимости
          api.getWorkerById(workerId).then(worker => {
            if (worker && worker.city === city) {
              setWorkerName(worker.name);
              setError('');
              // Показываем предупреждение, что это может быть другой сотрудник
              if (workerId.length > 2) {
                setError('Внимание: ID мог использоваться разными сотрудниками. Проверьте дату.');
              }
            } else {
              setWorkerName('');
              if (workerId.length > 2) setError('ID не найден в этом городе');
            }
          });
        }
      }).catch(() => {
        // Если API метод не поддерживается, используем старый метод
        api.getWorkerById(workerId).then(worker => {
          if (worker && worker.city === city) {
            setWorkerName(worker.name);
            setError('');
          } else {
            setWorkerName('');
            if (workerId.length > 2) setError('ID не найден в этом городе');
          }
        });
      });
    } else {
      setWorkerName('');
    }
  }, [workerId, city, date]);

  const validateReport = () => {
    const errors = [];
    
    // Валидация часов
    const hoursNum = parseFloat(hours);
    if (hoursNum > 12) {
      errors.push('Максимальное количество часов - 12');
    }
    if (hoursNum <= 0) {
      errors.push('Количество часов должно быть больше 0');
    }
    
    // Валидация кассы
    const cashNum = parseFloat(cash);
    if (cashNum > 450000) {
      errors.push('Максимальная сумма кассы - 450 000 ₽');
    }
    if (cashNum < 0) {
      errors.push('Сумма кассы не может быть отрицательной');
    }
    
    // Валидация кассы 2 (для объединенных точек)
    if (mergedPoint) {
      const cash2Num = parseFloat(cash2);
      if (cash2Num > 450000) {
        errors.push('Максимальная сумма кассы - 450 000 ₽');
      }
      if (cash2Num < 0) {
        errors.push('Сумма кассы не может быть отрицательной');
      }
    }
    
    // Валидация закупа
    const purchaseNum = parseFloat(purchase);
    if (purchaseNum > 150000) {
      errors.push('Максимальная сумма закупа - 150 000 ₽');
    }
    if (purchaseNum < 0) {
      errors.push('Сумма закупа не может быть отрицательной');
    }
    
    return errors;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    if (!workerName) {
      setError('Сначала введите корректный ID');
      setLoading(false);
      return;
    }

    // Валидация данных
    const validationErrors = validateReport();
    if (validationErrors.length > 0) {
      setError(validationErrors.join('. '));
      setLoading(false);
      return;
    }

    try {
      if (mergedPoint) {
        // Submit two reports, split hours
        const splitHours = parseFloat(hours) / 2;
        await Promise.all([
          api.submitReport({
            date, worker_id: workerId, point_id: parseInt(selectedPointId),
            hours: splitHours, cash: parseFloat(cash), purchase: parseFloat(purchase) || 0,
            comment: `(Объединено с ${mergedPoint.name}) ${comment}`, password
          }),
          api.submitReport({
            date, worker_id: workerId, point_id: mergedPoint.id,
            hours: splitHours, cash: parseFloat(cash2), purchase: 0,
            comment: `(Объединено с ${selectedPoint?.name}) ${comment}`, password
          })
        ]);
      } else {
        await api.submitReport({
          date,
          worker_id: workerId,
          point_id: parseInt(selectedPointId),
          hours: parseFloat(hours),
          cash: parseFloat(cash),
          purchase: parseFloat(purchase) || 0,
          comment,
          password
        });
      }
      setSuccess(true);
      // Reset form
      setHours('');
      setCash('');
      setCash2('');
      setPurchase('');
      setComment('');
      setPassword('');
    } catch (err: any) {
      setError(err.error || 'Ошибка при отправке');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <motion.div 
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        className="bg-white rounded-3xl p-8 text-center shadow-sm border border-stone-200 space-y-6"
      >
        <div className="bg-emerald-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto">
          <CheckCircle2 className="text-emerald-600 w-10 h-10" />
        </div>
        <div>
          <h2 className="text-2xl font-bold mb-2">Отчет отправлен!</h2>
          <p className="text-stone-500">Ваш отчет ожидает подтверждения администратором.</p>
        </div>
        <button 
          onClick={() => setSuccess(false)}
          className="w-full bg-emerald-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-emerald-600/20"
        >
          Отправить еще один
        </button>
      </motion.div>
    );
  }

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-black tracking-tight uppercase">Заполнение отчета</h2>
      
      <form onSubmit={handleSubmit} className="space-y-4">
        {/* Date Selection */}
        <div className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-2">Дата смены</label>
          <div className="grid grid-cols-2 gap-2">
            {dates.map(d => (
              <button
                key={d}
                type="button"
                onClick={() => setDate(d)}
                className={`py-2 px-3 rounded-xl text-sm font-bold transition-all ${
                  date === d ? 'bg-emerald-600 text-white shadow-md' : 'bg-stone-100 text-stone-600'
                }`}
              >
                {new Date(d).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' })}
              </button>
            ))}
          </div>
        </div>

        {/* Worker Info */}
        <div className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm space-y-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-1">Ваш ID</label>
            <input 
              type="text"
              value={workerId}
              onChange={(e) => setWorkerId(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-lg"
              placeholder="Введите ID"
              required
            />
          </div>
          {workerName && (
            <motion.div 
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              className="bg-emerald-50 p-3 rounded-xl flex items-center gap-3 border border-emerald-100"
            >
              <div className="bg-emerald-600 text-white p-1 rounded-full"><CheckCircle2 className="w-4 h-4" /></div>
              <p className="font-bold text-emerald-900">{workerName}</p>
            </motion.div>
          )}
        </div>

        {/* Work Details */}
        <div className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm space-y-4">
          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-1">Точка</label>
            <select 
              value={selectedPointId}
              onChange={(e) => setSelectedPointId(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
              required
            >
              <option value="">Выберите точку</option>
              {points.map(p => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">Часы (макс. 12)</label>
              <input 
                type="number"
                step="0.5"
                max="12"
                min="0"
                value={hours}
                onChange={(e) => setHours(e.target.value)}
                className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                placeholder="0.0"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">
                {mergedPoint ? `Касса (${selectedPoint?.name}) - макс. 450 000 ₽` : 'Касса (макс. 450 000 ₽)'}
              </label>
              <input 
                type="number"
                min="0"
                max="450000"
                value={cash}
                onChange={(e) => setCash(e.target.value)}
                className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                placeholder="0"
                required
              />
            </div>
          </div>

          {mergedPoint && (
            <motion.div 
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              className="bg-stone-50 p-4 rounded-2xl border border-stone-100"
            >
              <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">
                Касса ({mergedPoint.name}) - макс. 450 000 ₽
              </label>
              <input 
                type="number"
                min="0"
                max="450000"
                value={cash2}
                onChange={(e) => setCash2(e.target.value)}
                className="w-full bg-white border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                placeholder="0"
                required={!!mergedPoint}
              />
              <p className="text-[10px] font-bold text-emerald-600 mt-2 uppercase tracking-tight">
                * Часы будут разделены поровну ({parseFloat(hours) / 2 || 0} ч на каждую точку)
              </p>
            </motion.div>
          )}

          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-1">Закуп (макс. 150 000 ₽)</label>
            <input 
              type="number"
              min="0"
              max="150000"
              value={purchase}
              onChange={(e) => setPurchase(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
              placeholder="0"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-1">Комментарий</label>
            <textarea 
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-medium min-h-[80px]"
              placeholder="Опционально..."
            />
          </div>
        </div>

        {/* Security */}
        <div className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm">
          <label className="block text-[10px] font-bold text-stone-400 uppercase tracking-wider mb-1">Пароль доступа</label>
          <input 
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-stone-50 border-none rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
            placeholder="••••"
            required
          />
        </div>

        {error && (
          <div className="bg-red-50 text-red-600 p-4 rounded-2xl flex items-center gap-3 border border-red-100">
            <AlertCircle className="w-5 h-5 shrink-0" />
            <p className="text-sm font-bold">{error}</p>
          </div>
        )}

        <button 
          type="submit"
          disabled={loading}
          className="w-full bg-emerald-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-emerald-600/20 active:scale-[0.98] transition-all flex items-center justify-center gap-2 disabled:opacity-50"
        >
          {loading ? 'Отправка...' : <><Send className="w-5 h-5" /> Отправить отчет</>}
        </button>
      </form>
    </div>
  );
}
